            return self._s(200, json.dumps(_g_cached("drv|%s|%s|%s|%s|%s|%s"%(_dq,_dm,_dp,_dk,_ds,_do), lambda: drive_list(_dq,_dm,_dp,_dk,_ds,_do), fresh=_df)))
